     5→//! Query operations for Gallops JSON
     6→//!
     7→//! Implements read operations: muster, saddle, parade, retire.
     8→//! All operations read from Gallops JSON and optionally paddock files.
     9→
    10→use crate::jjrf_favor::jjrf_Firemark as Firemark;
    11→use crate::jjrf_favor::jjrf_Coronet as Coronet;
    12→use crate::jjrg_gallops::{jjrg_Gallops as Gallops, jjrg_HeatStatus as HeatStatus, jjrg_PaceState as PaceState, jjrg_Pace as Pace};
    13→use crate::jjrs_steeplechase::{jjrs_SteeplechaseEntry, jjrs_get_entries, jjrs_ReinArgs};
    14→use serde::Serialize;
    15→use std::fs;
    16→
    17→// ============================================================================
    18→// Muster - List all Heats with summary information
    19→// ============================================================================
    20→
    21→/// Arguments for muster command
    22→#[derive(Debug)]
    23→pub struct jjrq_MusterArgs {
    24→    pub file: std::path::PathBuf,
    25→}
    26→
    27→/// Run the muster command - list Heats as TSV
    28→pub fn jjrq_run_muster(args: jjrq_MusterArgs) -> i32 {
    29→    let gallops = match Gallops::jjrg_load(&args.file) {
    30→        Ok(g) => g,
    31→        Err(e) => {
    32→            eprintln!("jjx_muster: error: {}", e);
    33→            return 1;
    34→        }
    35→    };
    36→
    37→    // Collect heats with status info for sorting
    38→    let mut heats_by_status: Vec<(&String, &crate::jjrg_gallops::jjrg_Heat)> = gallops.heats.iter().collect();
    39→
    40→    // Sort: racing first, then stabled, then retired
    41→    heats_by_status.sort_by(|a, b| {
    42→        let a_status_order = match a.1.status {
    43→            HeatStatus::Racing => 0,
    44→            HeatStatus::Stabled => 1,
    45→            HeatStatus::Retired => 2,
    46→        };
    47→        let b_status_order = match b.1.status {
    48→            HeatStatus::Racing => 0,
    49→            HeatStatus::Stabled => 1,
    50→            HeatStatus::Retired => 2,
    51→        };
    52→        a_status_order.cmp(&b_status_order)
    53→    });
    54→
    55→    for (key, heat) in heats_by_status {
    56→        let total_pace_count = heat.paces.len();
    57→
    58→        // Count actionable paces (rough or bridled)
    59→        let remaining_count = heat.paces.values().filter(|pace| {
    60→            if let Some(tack) = pace.tacks.first() {
    61→                matches!(tack.state, PaceState::Rough | PaceState::Bridled)
    62→            } else {
    63→                false
    64→            }
    65→        }).count();
    66→
    67→        let status_str = match heat.status {
    68→            HeatStatus::Racing => "racing",
    69→            HeatStatus::Stabled => "stabled",
    70→            HeatStatus::Retired => "retired",
    71→        };
    72→
    73→        println!("{}\t{}\t{}\t{}\t{}", key, heat.silks, status_str, remaining_count, total_pace_count);
    74→    }
    75→
    76→    0
    77→}
    78→
    79→// ============================================================================
    80→// Saddle - Return context needed to saddle up on a Heat
    81→// ============================================================================
    82→
    83→/// Arguments for saddle command
    84→#[derive(Debug)]
    85→pub struct jjrq_SaddleArgs {
    86→    pub file: std::path::PathBuf,
    87→    pub firemark: Firemark,
    88→}
    89→
    90→/// Output structure for saddle command
    91→#[derive(Serialize)]
    92→pub(crate) struct zjjrq_SaddleOutput {
    93→    pub(crate) heat_silks: String,
    94→    pub(crate) paddock_file: String,
    95→    pub(crate) paddock_content: String,
    96→    #[serde(skip_serializing_if = "Option::is_none")]
    97→    pub(crate) pace_coronet: Option<String>,
    98→    #[serde(skip_serializing_if = "Option::is_none")]
    99→    pub(crate) pace_silks: Option<String>,
   100→    #[serde(skip_serializing_if = "Option::is_none")]
   101→    pub(crate) pace_state: Option<String>,
   102→    #[serde(skip_serializing_if = "Option::is_none")]
   103→    pub(crate) spec: Option<String>,
   104→    #[serde(skip_serializing_if = "Option::is_none")]
   105→    pub(crate) direction: Option<String>,
   106→    pub(crate) recent_work: Vec<jjrs_SteeplechaseEntry>,
   107→}
   108→
   109→/// Run the saddle command - return Heat context
   110→pub fn jjrq_run_saddle(args: jjrq_SaddleArgs) -> i32 {
   111→    let gallops = match Gallops::jjrg_load(&args.file) {
   112→        Ok(g) => g,
   113→        Err(e) => {
   114→            eprintln!("jjx_saddle: error: {}", e);
   115→            return 1;
   116→        }
   117→    };
   118→
   119→    let heat_key = args.firemark.jjrf_display();
   120→    let heat = match gallops.heats.get(&heat_key) {
   121→        Some(h) => h,
   122→        None => {
   123→            eprintln!("jjx_saddle: error: Heat '{}' not found", heat_key);
   124→            return 1;
   125→        }
   126→    };
   127→
   128→    // Check if heat is stabled (cannot saddle stabled heat)
   129→    if heat.status == HeatStatus::Stabled {
   130→        eprintln!("jjx_saddle: error: Cannot saddle stabled heat '{}'", heat_key);
   131→        return 1;
   132→    }
   133→
   134→    // Read paddock file content
   135→    let paddock_content = match fs::read_to_string(&heat.paddock_file) {
   136→        Ok(content) => content,
   137→        Err(e) => {
   138→            eprintln!("jjx_saddle: error reading paddock file '{}': {}", heat.paddock_file, e);
   139→            return 1;
   140→        }
   141→    };
   142→
   143→    // Get recent steeplechase entries
   144→    let recent_work = jjrs_get_entries(&jjrs_ReinArgs {
   145→        firemark: args.firemark.jjrf_as_str().to_string(),
   146→        limit: 10,
   147→    }).unwrap_or_default();
   148→
   149→    // Find first actionable pace (rough or bridled)
   150→    let mut output = zjjrq_SaddleOutput {
   151→        heat_silks: heat.silks.clone(),
   152→        paddock_file: heat.paddock_file.clone(),
   153→        paddock_content,
   154→        pace_coronet: None,
   155→        pace_silks: None,
   156→        pace_state: None,
   157→        spec: None,
   158→        direction: None,
   159→        recent_work,
   160→    };
   161→
   162→    for coronet_key in &heat.order {
   163→        if let Some(pace) = heat.paces.get(coronet_key) {
   164→            if let Some(tack) = pace.tacks.first() {
   165→                match tack.state {
   166→                    PaceState::Rough | PaceState::Bridled => {
   167→                        output.pace_coronet = Some(coronet_key.clone());
   168→                        output.pace_silks = Some(tack.silks.clone());
   169→                        output.pace_state = Some(match tack.state {
   170→                            PaceState::Rough => "rough".to_string(),
   171→                            PaceState::Bridled => "bridled".to_string(),
   172→                            _ => unreachable!(),
   173→                        });
   174→                        output.spec = Some(tack.text.clone());
   175→                        if tack.state == PaceState::Bridled {
   176→                            output.direction = tack.direction.clone();
   177→                        }
   178→                        break;
   179→                    }
   180→                    _ => continue,
   181→                }
   182→            }
   183→        }
   184→    }
   185→
   186→    // Output JSON
   187→    match serde_json::to_string_pretty(&output) {
   188→        Ok(json) => {
   189→            println!("{}", json);
   190→            0
   191→        }
   192→        Err(e) => {
   193→            eprintln!("jjx_saddle: error serializing output: {}", e);
   194→            1
   195→        }
   196→    }
   197→}
   198→
   199→// ============================================================================
   200→// Parade - Display comprehensive Heat status for project review
   201→// ============================================================================
   202→
   203→/// Output format modes for parade command
   204→#[derive(Debug, Clone, Copy, Default, PartialEq, Eq)]
   205→pub enum jjrq_ParadeFormat {
   206→    /// One line per pace: [state] silks (₢coronet)
   207→    Overview,
   208→    /// Numbered list: N. [state] silks (₢coronet)
   209→    Order,
   210→    /// Full tack text for one pace (requires --pace)
   211→    Detail,
   212→    /// Paddock + all paces with tack text (default)
   213→    #[default]
   214→    Full,
   215→}
   216→
   217→/// Arguments for parade command
   218→#[derive(Debug)]
   219→pub struct jjrq_ParadeArgs {
   220→    pub file: std::path::PathBuf,
   221→    pub firemark: Firemark,
   222→    pub format: jjrq_ParadeFormat,
   223→    pub pace: Option<String>,
   224→    pub remaining: bool,
   225→}
   226→
   227→/// Run the parade command - display comprehensive Heat status
   228→pub fn jjrq_run_parade(args: jjrq_ParadeArgs) -> i32 {
   229→    // Validate: detail format requires --pace
   230→    if args.format == jjrq_ParadeFormat::Detail && args.pace.is_none() {
   231→        eprintln!("jjx_parade: error: --format detail requires --pace <coronet>");
   232→        return 1;
   233→    }
   234→
   235→    let gallops = match Gallops::jjrg_load(&args.file) {
   236→        Ok(g) => g,
   237→        Err(e) => {
   238→            eprintln!("jjx_parade: error: {}", e);
   239→            return 1;
   240→        }
   241→    };
   242→
   243→    let heat_key = args.firemark.jjrf_display();
   244→    let heat = match gallops.heats.get(&heat_key) {
   245→        Some(h) => h,
   246→        None => {
   247→            eprintln!("jjx_parade: error: Heat '{}' not found", heat_key);
   248→            return 1;
   249→        }
   250→    };
   251→
   252→    match args.format {
   253→        jjrq_ParadeFormat::Overview => {
   254→            for coronet_key in &heat.order {
   255→                if let Some(pace) = heat.paces.get(coronet_key) {
   256→                    if let Some(tack) = pace.tacks.first() {
   257→                        // Skip complete/abandoned if --remaining
   258→                        if args.remaining && (tack.state == PaceState::Complete || tack.state == PaceState::Abandoned) {
   259→                            continue;
   260→                        }
   261→                        let state_str = zjjrq_pace_state_str(&tack.state);
   262→                        println!("[{}] {} ({})", state_str, tack.silks, coronet_key);
   263→                    }
   264→                }
   265→            }
   266→        }
   267→        jjrq_ParadeFormat::Order => {
   268→            let mut num = 0;
   269→            for coronet_key in &heat.order {
   270→                if let Some(pace) = heat.paces.get(coronet_key) {
   271→                    if let Some(tack) = pace.tacks.first() {
   272→                        // Skip complete/abandoned if --remaining
   273→                        if args.remaining && (tack.state == PaceState::Complete || tack.state == PaceState::Abandoned) {
   274→                            continue;
   275→                        }
   276→                        num += 1;
   277→                        let state_str = zjjrq_pace_state_str(&tack.state);
   278→                        println!("{}. [{}] {} ({})", num, state_str, tack.silks, coronet_key);
   279→                    }
   280→                }
   281→            }
   282→        }
   283→        jjrq_ParadeFormat::Detail => {
   284→            let pace_arg = args.pace.as_ref().unwrap();
   285→            let (coronet_key, pace) = match zjjrq_resolve_pace(heat, pace_arg) {
   286→                Some(result) => result,
   287→                None => {
   288→                    eprintln!("jjx_parade: error: Pace '{}' not found in Heat '{}' (tried coronet and silks)", pace_arg, heat_key);
   289→                    return 1;
   290→                }
   291→            };
   292→            if let Some(tack) = pace.tacks.first() {
   293→                let state_str = zjjrq_pace_state_str(&tack.state);
   294→                println!("Pace: {} ({})", tack.silks, coronet_key);
   295→                println!("State: {}", state_str);
   296→                println!("Heat: {}", heat_key);
   297→                println!();
   298→                println!("{}", tack.text);
   299→                if let Some(ref direction) = tack.direction {
   300→                    println!();
   301→                    println!("Direction: {}", direction);
   302→                }
   303→            }
   304→        }
   305→        jjrq_ParadeFormat::Full => {
   306→            // Read paddock file content
   307→            let paddock_content = match fs::read_to_string(&heat.paddock_file) {
   308→                Ok(content) => content,
   309→                Err(e) => {
   310→                    eprintln!("jjx_parade: error reading paddock file '{}': {}", heat.paddock_file, e);
   311→                    return 1;
   312→                }
   313→            };
   314→
   315→            let status_str = match heat.status {
   316→                HeatStatus::Racing => "racing",
   317→                HeatStatus::Stabled => "stabled",
   318→                HeatStatus::Retired => "retired",
   319→            };
   320→
   321→            println!("Heat: {} ({})", heat.silks, heat_key);
   322→            println!("Status: {}", status_str);
   323→            println!("Created: {}", heat.creation_time);
   324→            println!();
   325→            println!("## Paddock");
   326→            println!();
   327→            println!("{}", paddock_content);
   328→            println!();
   329→            println!("## Paces");
   330→            println!();
   331→
   332→            for coronet_key in &heat.order {
   333→                if let Some(pace) = heat.paces.get(coronet_key) {
   334→                    if let Some(tack) = pace.tacks.first() {
   335→                        // Skip complete/abandoned if --remaining
   336→                        if args.remaining && (tack.state == PaceState::Complete || tack.state == PaceState::Abandoned) {
   337→                            continue;
   338→                        }
   339→                        let state_str = zjjrq_pace_state_str(&tack.state);
   340→                        println!("### {} ({}) [{}]", tack.silks, coronet_key, state_str);
   341→                        println!();
   342→                        println!("{}", tack.text);
   343→                        if let Some(ref direction) = tack.direction {
   344→                            println!();
   345→                            println!("**Direction:** {}", direction);
   346→                        }
   347→                        println!();
   348→                    }
   349→                }
   350→            }
   351→        }
   352→    }
   353→
   354→    0
   355→}
   356→
   357→/// Helper to resolve pace by coronet or silks
   358→///
   359→/// First tries to parse pace_arg as a Coronet and lookup by coronet key.
   360→/// If that fails, iterates heat.paces to find a pace where tacks[0].silks matches pace_arg.
   361→/// Returns tuple of (coronet_key, pace_ref) if found.
   362→fn zjjrq_resolve_pace<'a>(
   363→    heat: &'a crate::jjrg_gallops::jjrg_Heat,
   364→    pace_arg: &str,
   365→) -> Option<(&'a String, &'a Pace)> {
   366→    // Try parsing as Coronet first
   367→    if let Ok(coronet) = Coronet::jjrf_parse(pace_arg) {
   368→        let coronet_key = coronet.jjrf_display();
   369→        if let Some((key, pace)) = heat.paces.get_key_value(&coronet_key) {
   370→            return Some((key, pace));
   371→        }
   372→    }
   373→
   374→    // Fallback: search by silks
   375→    for (coronet_key, pace) in &heat.paces {
   376→        if let Some(tack) = pace.tacks.first() {
   377→            if tack.silks == pace_arg {
   378→                return Some((coronet_key, pace));
   379→            }
   380→        }
   381→    }
   382→
   383→    None
   384→}
   385→
   386→/// Helper to convert PaceState to display string
   387→fn zjjrq_pace_state_str(state: &PaceState) -> &'static str {
   388→    match state {
   389→        PaceState::Rough => "rough",
   390→        PaceState::Bridled => "bridled",
   391→        PaceState::Complete => "complete",
   392→        PaceState::Abandoned => "abandoned",
   393→    }
   394→}
   395→
   396→// ============================================================================
   397→// Retire - Extract complete Heat data for archival trophy
   398→// ============================================================================
   399→
   400→/// Arguments for retire command
   401→#[derive(Debug)]
   402→pub struct jjrq_RetireArgs {
   403→    pub file: std::path::PathBuf,
   404→    pub firemark: Firemark,
   405→}
   406→
   407→/// Output structure for retire command
   408→#[derive(Serialize)]
   409→pub(crate) struct zjjrq_RetireOutput {
   410→    pub(crate) firemark: String,
   411→    pub(crate) silks: String,
   412→    pub(crate) created: String,
   413→    pub(crate) status: String,
   414→    pub(crate) paddock_file: String,
   415→    pub(crate) paddock_content: String,
   416→    pub(crate) paces: Vec<zjjrq_RetirePace>,
   417→    // TODO: steeplechase array from jjx_rein
   418→    // steeplechase: Vec<SteeplechaseEntry>,
   419→}
   420→
   421→/// Pace structure for retire output (full tack history)
   422→#[derive(Serialize)]
   423→pub(crate) struct zjjrq_RetirePace {
   424→    pub(crate) coronet: String,
   425→    pub(crate) silks: String,
   426→    pub(crate) tacks: Vec<zjjrq_RetireTack>,
   427→}
   428→
   429→/// Tack structure for retire output
   430→#[derive(Serialize)]
   431→pub(crate) struct zjjrq_RetireTack {
   432→    pub(crate) ts: String,
   433→    pub(crate) state: String,
   434→    pub(crate) text: String,
   435→    #[serde(skip_serializing_if = "Option::is_none")]
   436→    pub(crate) direction: Option<String>,
   437→}
   438→
   439→/// Run the retire command - extract complete Heat data for archival
   440→pub fn jjrq_run_retire(args: jjrq_RetireArgs) -> i32 {
   441→    let gallops = match Gallops::jjrg_load(&args.file) {
   442→        Ok(g) => g,
   443→        Err(e) => {
   444→            eprintln!("jjx_retire: error: {}", e);
   445→            return 1;
   446→        }
   447→    };
   448→
   449→    let heat_key = args.firemark.jjrf_display();
   450→    let heat = match gallops.heats.get(&heat_key) {
   451→        Some(h) => h,
   452→        None => {
   453→            eprintln!("jjx_retire: error: Heat '{}' not found", heat_key);
   454→            return 1;
   455→        }
   456→    };
   457→
   458→    // Read paddock file content
   459→    let paddock_content = match fs::read_to_string(&heat.paddock_file) {
   460→        Ok(content) => content,
   461→        Err(e) => {
   462→            eprintln!("jjx_retire: error reading paddock file '{}': {}", heat.paddock_file, e);
   463→            return 1;
   464→        }
   465→    };
   466→
   467→    // Build paces array with full tack history, ordered per Heat's order array
   468→    let mut paces = Vec::new();
   469→    for coronet_key in &heat.order {
   470→        if let Some(pace) = heat.paces.get(coronet_key) {
   471→            let tacks: Vec<zjjrq_RetireTack> = pace.tacks.iter().map(|tack| {
   472→                zjjrq_RetireTack {
   473→                    ts: tack.ts.clone(),
   474→                    state: match tack.state {
   475→                        PaceState::Rough => "rough".to_string(),
   476→                        PaceState::Bridled => "bridled".to_string(),
   477→                        PaceState::Complete => "complete".to_string(),
   478→                        PaceState::Abandoned => "abandoned".to_string(),
   479→                    },
   480→                    text: tack.text.clone(),
   481→                    direction: tack.direction.clone(),
   482→                }
   483→            }).collect();
   484→
   485→            paces.push(zjjrq_RetirePace {
   486→                coronet: coronet_key.clone(),
   487→                silks: pace.tacks.first().map(|t| t.silks.clone()).unwrap_or_default(),
   488→                tacks,
   489→            });
   490→        }
   491→    }
   492→
   493→    let output = zjjrq_RetireOutput {
   494→        firemark: heat_key.clone(),
   495→        silks: heat.silks.clone(),
   496→        created: heat.creation_time.clone(),
   497→        status: match heat.status {
   498→            HeatStatus::Racing => "racing".to_string(),
   499→            HeatStatus::Stabled => "stabled".to_string(),
   500→            HeatStatus::Retired => "retired".to_string(),
   501→        },
   502→        paddock_file: heat.paddock_file.clone(),
   503→        paddock_content,
   504→        paces,
   505→        // TODO: Call jjx_rein internally to get steeplechase entries
   506→    };
   507→
   508→    // Output JSON
   509→    match serde_json::to_string_pretty(&output) {
   510→        Ok(json) => {
   511→            println!("{}", json);
   512→            0
   513→        }
   514→        Err(e) => {
   515→            eprintln!("jjx_retire: error serializing output: {}", e);
   516→            1
   517→        }
   518→    }
   519→}
